<script setup>
import { Head, useForm } from '@inertiajs/vue3'
import { CloudArrowUpIcon, XMarkIcon } from '@heroicons/vue/24/outline'
import AppLayout from '../../Layouts/AppLayout.vue'
import Button from '../../Components/UI/Button.vue'
import Input from '../../Components/UI/Input.vue'
import Card from '../../Components/UI/Card.vue'
import Select from '../../Components/UI/Select.vue'
import Textarea from '../../Components/UI/Textarea.vue'

const props = defineProps({
    categories: Array,
    tags: Array,
    statuses: Array,
})

const form = useForm({
    file: null,
    title: '',
    category_id: '',
    tag_ids: [],
    issue_date: '',
    expiry_date: '',
    status: 'active',
    notes: '',
})

const submit = () => {
    form.post('/documents')
}
</script>

<template>
    <Head title="Upload Document" />

    <AppLayout>
        <div class="mx-auto max-w-3xl space-y-6">
            <header>
                <h1 class="text-3xl font-bold tracking-tight text-zinc-900">Upload Document</h1>
                <p class="mt-1 text-sm text-zinc-500">Add a new document to your library. PDF, JPG, PNG, and WebP are supported.</p>
            </header>

            <form @submit.prevent="submit" class="space-y-6">
                <Card title="Document File">
                    <div class="space-y-4">
                        <div class="flex items-center justify-center rounded-lg border-2 border-dashed border-zinc-200 bg-zinc-50/50 p-6 transition-colors hover:border-zinc-300">
                            <div class="text-center">
                                <CloudArrowUpIcon class="mx-auto h-10 w-10 text-zinc-400" />
                                <div class="mt-4 flex text-sm text-zinc-600">
                                    <label class="relative cursor-pointer rounded-md font-semibold text-zinc-900 hover:text-zinc-700">
                                        <span>Select a file</span>
                                        <input type="file" accept=".pdf,.jpg,.jpeg,.png,.webp" @input="form.file = $event.target.files[0]" class="sr-only">
                                    </label>
                                    <p class="pl-1">or drag and drop</p>
                                </div>
                                <p class="text-xs text-zinc-500">PDF, PNG, JPG up to 10MB</p>
                            </div>
                        </div>
                        <div v-if="form.file" class="flex items-center justify-between rounded-lg bg-zinc-100 px-4 py-2 text-sm text-zinc-700">
                            <span class="truncate font-medium">{{ form.file.name }}</span>
                            <button type="button" @click="form.file = null" class="text-zinc-400 hover:text-zinc-600">
                                <XMarkIcon class="h-5 w-5" />
                            </button>
                        </div>
                        <p v-if="form.errors.file" class="text-sm text-red-600">{{ form.errors.file }}</p>
                    </div>
                </Card>

                <Card title="General Information">
                    <div class="grid gap-4 sm:grid-cols-2">
                        <div class="sm:col-span-2">
                            <Input v-model="form.title" label="Title" placeholder="e.g. Identity Card" :error="form.errors.title" required />
                        </div>

                        <Select
                            v-model="form.category_id"
                            label="Category"
                            :options="categories.map(c => ({ value: c.id, label: c.name }))"
                            placeholder="No category"
                            :error="form.errors.category_id"
                        />

                        <Select
                            v-model="form.status"
                            label="Status"
                            :options="statuses.map(s => ({ value: s, label: s.charAt(0).toUpperCase() + s.slice(1) }))"
                            :error="form.errors.status"
                            required
                        />

                        <Input v-model="form.issue_date" type="date" label="Issue Date" :error="form.errors.issue_date" />
                        <Input v-model="form.expiry_date" type="date" label="Expiry Date" :error="form.errors.expiry_date" />

                        <div class="sm:col-span-2">
                            <Textarea v-model="form.notes" label="Notes" placeholder="Any additional details..." :error="form.errors.notes" />
                        </div>
                    </div>
                </Card>

                <div class="flex items-center justify-end gap-3">
                    <Button href="/documents" variant="secondary">Cancel</Button>
                    <Button type="submit" :disabled="form.processing">
                        {{ form.processing ? 'Uploading...' : 'Save Document' }}
                    </Button>
                </div>
            </form>
        </div>
    </AppLayout>
</template>
